#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &x,const char &c='\n'){print(x<0?putchar('-'),-x:x);putchar(c);}
const int N=3e4+10;int n;
template <typename T> inline void Swap(T&x,T&y){T t=x;x=y;y=t;}
inline char Get(){char x;do x=getchar();while(x!='Q'&&x!='C'&&x!='D');return x;}
namespace LCT
{
	int ch[N][2],fa[N];bool tg[N];inline void Rev(int x){Swap(ch[x][0],ch[x][1]);tg[x]^=1;}
	inline void pushdown(int x){if(tg[x]){Rev(ch[x][0]);Rev(ch[x][1]);tg[x]=false;}}
	inline bool nrt(const int &x){return ch[fa[x]][0]==x||ch[fa[x]][1]==x;}
	inline void rotate(int x)
	{
		int y=fa[x],z=fa[y];bool k=ch[y][1]==x;
		if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
		if(w)fa[w]=y;fa[fa[y]=x]=z;
	}
	inline void pushall(int x){if(nrt(x))pushall(fa[x]);pushdown(x);}
	inline void splay(int x)
	{
		pushall(x);const int &y=fa[x];
		while(nrt(x)){nrt(y)?rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y):void(),rotate(x);}
	}
	inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),ch[x][1]=y;}
	inline void makeRt(int x){access(x);splay(x);Rev(x);}
	inline void split(int x,int y){makeRt(x);access(y);splay(y);}
	inline void lnk(int x,int y){makeRt(x);fa[x]=y;}
	inline void cut(int x,int y){split(x,y);fa[x]=ch[y][0]=0;}
	inline int fndRt(int x){access(x);splay(x);while(ch[x][0])pushdown(x),x=ch[x][0];return x;}
}
using namespace LCT;
int main()
{
	n=read();int Q=read(),u,v;while(Q--)switch(Get()) 
	{
		case 'Q': u=read();v=read();puts(fndRt(u)==fndRt(v)?"Yes":"No");break;
		case 'C': u=read();v=read();lnk(u,v);break;
		case 'D': u=read();v=read();cut(u,v);break;
	}
}
